-- ============================================================
-- EduBridge AI — Complete Supabase Schema + Seed Data
-- Platform helping international students find US universities
-- and scholarships.
-- ============================================================

-- ============================================================
-- 1. SCHEMA
-- ============================================================

-- ---------- profiles ----------
CREATE TABLE profiles (
  id UUID PRIMARY KEY REFERENCES auth.users(id) ON DELETE CASCADE,
  full_name TEXT NOT NULL DEFAULT '',
  email TEXT NOT NULL DEFAULT '',
  country TEXT DEFAULT '',
  date_of_birth DATE,
  gender TEXT,
  first_generation BOOLEAN DEFAULT false,
  low_income BOOLEAN DEFAULT false,
  gpa NUMERIC(4,2),
  gpa_scale TEXT DEFAULT '4.0',
  intended_major TEXT,
  education_level TEXT DEFAULT 'high_school',
  academic_strengths TEXT,
  extracurriculars TEXT[],
  sat_score INTEGER,
  act_score INTEGER,
  toefl_score INTEGER,
  ielts_score NUMERIC(2,1),
  english_level INTEGER,
  test_optional_preference BOOLEAN DEFAULT false,
  destination_country TEXT DEFAULT 'US',
  target_start_term TEXT,
  preferred_school_type TEXT,
  preferred_states TEXT[],
  preferred_campus_size TEXT,
  preferred_setting TEXT,
  annual_family_income TEXT,
  max_annual_budget INTEGER,
  needs_full_scholarship BOOLEAN DEFAULT false,
  willing_community_college_transfer BOOLEAN DEFAULT false,
  needs_f1_visa BOOLEAN DEFAULT true,
  plans_to_work BOOLEAN DEFAULT false,
  work_goals TEXT,
  support_needs TEXT[],
  onboarding_completed BOOLEAN DEFAULT false,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

ALTER TABLE profiles ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view own profile"
  ON profiles FOR SELECT
  USING (auth.uid() = id);

CREATE POLICY "Users can insert own profile"
  ON profiles FOR INSERT
  WITH CHECK (auth.uid() = id);

CREATE POLICY "Users can update own profile"
  ON profiles FOR UPDATE
  USING (auth.uid() = id);

-- Trigger: auto-create profile on signup
CREATE OR REPLACE FUNCTION handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO profiles (id, full_name, email)
  VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'full_name', ''),
    COALESCE(NEW.email, '')
  );
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION handle_new_user();

-- ---------- universities ----------
CREATE TABLE universities (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  city TEXT NOT NULL,
  state TEXT NOT NULL,
  type TEXT NOT NULL,
  acceptance_rate NUMERIC(5,2),
  avg_sat INTEGER,
  avg_act INTEGER,
  min_toefl INTEGER,
  min_ielts NUMERIC(2,1),
  tuition_in_state INTEGER,
  tuition_out_of_state INTEGER,
  tuition_international INTEGER,
  room_and_board INTEGER,
  estimated_total_cost INTEGER,
  avg_financial_aid INTEGER,
  international_aid_available BOOLEAN DEFAULT false,
  merit_scholarships_available BOOLEAN DEFAULT false,
  need_blind_international BOOLEAN DEFAULT false,
  test_optional BOOLEAN DEFAULT false,
  total_enrollment INTEGER,
  international_student_pct NUMERIC(4,1),
  student_faculty_ratio TEXT,
  popular_majors TEXT[],
  campus_setting TEXT,
  website TEXT,
  description TEXT,
  image_url TEXT,
  us_news_rank INTEGER,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_universities_state ON universities(state);
CREATE INDEX idx_universities_type ON universities(type);
CREATE INDEX idx_universities_acceptance_rate ON universities(acceptance_rate);
CREATE INDEX idx_universities_tuition_international ON universities(tuition_international);

ALTER TABLE universities ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Universities are publicly readable"
  ON universities FOR SELECT
  USING (true);

-- ---------- scholarships ----------
CREATE TABLE scholarships (
  id SERIAL PRIMARY KEY,
  name TEXT NOT NULL,
  slug TEXT UNIQUE NOT NULL,
  provider TEXT NOT NULL,
  type TEXT NOT NULL,
  amount_min INTEGER,
  amount_max INTEGER,
  covers_tuition BOOLEAN DEFAULT false,
  covers_living BOOLEAN DEFAULT false,
  renewable BOOLEAN DEFAULT false,
  duration_years INTEGER DEFAULT 1,
  eligible_countries TEXT[],
  eligible_majors TEXT[],
  min_gpa NUMERIC(3,2),
  min_toefl INTEGER,
  min_ielts NUMERIC(2,1),
  education_level TEXT[],
  income_requirement TEXT,
  first_gen_only BOOLEAN DEFAULT false,
  deadline TEXT,
  application_url TEXT,
  description TEXT,
  requirements TEXT,
  university_id INTEGER REFERENCES universities(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_scholarships_type ON scholarships(type);
CREATE INDEX idx_scholarships_university_id ON scholarships(university_id);
CREATE INDEX idx_scholarships_min_gpa ON scholarships(min_gpa);

ALTER TABLE scholarships ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Scholarships are publicly readable"
  ON scholarships FOR SELECT
  USING (true);

-- ---------- saved_matches ----------
CREATE TABLE saved_matches (
  id SERIAL PRIMARY KEY,
  user_id UUID REFERENCES profiles(id) ON DELETE CASCADE,
  university_id INTEGER REFERENCES universities(id),
  scholarship_id INTEGER REFERENCES scholarships(id),
  match_score INTEGER,
  match_reasons TEXT[],
  estimated_net_cost INTEGER,
  difficulty_level TEXT,
  status TEXT DEFAULT 'recommended',
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_saved_matches_user_id ON saved_matches(user_id);

ALTER TABLE saved_matches ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can manage own matches"
  ON saved_matches FOR ALL
  USING (auth.uid() = user_id);

-- ---------- chat_messages ----------
CREATE TABLE chat_messages (
  id SERIAL PRIMARY KEY,
  user_id UUID REFERENCES profiles(id) ON DELETE CASCADE,
  role TEXT NOT NULL,
  content TEXT NOT NULL,
  created_at TIMESTAMPTZ DEFAULT now()
);

CREATE INDEX idx_chat_messages_user_created ON chat_messages(user_id, created_at);

ALTER TABLE chat_messages ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can manage own chat messages"
  ON chat_messages FOR ALL
  USING (auth.uid() = user_id);


-- ============================================================
-- 2. SEED DATA — UNIVERSITIES
