INSERT INTO universities (name, slug, city, state, type, acceptance_rate, avg_sat, avg_act, min_toefl, min_ielts, tuition_in_state, tuition_out_of_state, tuition_international, room_and_board, estimated_total_cost, avg_financial_aid, international_aid_available, merit_scholarships_available, need_blind_international, test_optional, total_enrollment, international_student_pct, student_faculty_ratio, popular_majors, campus_setting, website, description, us_news_rank) VALUES
('Harvard University', 'harvard', 'Cambridge', 'MA', 'private_nonprofit', 3.41, 1520, 34, 100, 7.0, 56550, 56550, 56550, 21130, 77680, 55000, true, false, true, true, 22947, 13.0, '6:1', ARRAY['Economics','Computer Science','Political Science','Mathematics','Biology'], 'urban', 'https://www.harvard.edu', 'Harvard meets 100% of demonstrated financial need for all admitted students including international students. About 55% of students receive need-based scholarships. The average grant covers most of tuition and fees.', 3),
('Massachusetts Institute of Technology', 'mit', 'Cambridge', 'MA', 'private_nonprofit', 3.96, 1540, 35, 100, 7.0, 57986, 57986, 57986, 19680, 77666, 53000, true, false, true, true, 11520, 11.3, '3:1', ARRAY['Computer Science','Engineering','Mathematics','Physics','Biology'], 'urban', 'https://www.mit.edu', 'MIT is need-blind for international students and meets 100% of demonstrated financial need. Over 60% of undergraduates receive MIT scholarships. Strong support for international STEM students.', 2),
('Stanford University', 'stanford', 'Stanford', 'CA', 'private_nonprofit', 3.68, 1530, 34, 100, 7.0, 56169, 56169, 56169, 19134, 75303, 56000, true, false, true, true, 17534, 12.8, '5:1', ARRAY['Computer Science','Engineering','Biology','Economics','Psychology'], 'suburban', 'https://www.stanford.edu', 'Stanford meets 100% of demonstrated financial need for admitted students. Families with income below $75k pay no tuition, room, or board. Generous financial aid extends to international students.', 4),
