('Columbia University', 'columbia', 'New York', 'NY', 'private_nonprofit', 3.85, 1530, 34, 100, 7.0, 65524, 65524, 65524, 16800, 82324, 55000, true, false, true, true, 33413, 18.1, '6:1', ARRAY['Computer Science','Economics','Political Science','Biology','Psychology'], 'urban', 'https://www.columbia.edu', 'Located in New York City, Columbia offers unparalleled access to internships and cultural experiences. Need-blind for international students with 100% need met. Strong Core Curriculum.', 12),
('University of Pennsylvania', 'upenn', 'Philadelphia', 'PA', 'private_nonprofit', 5.37, 1520, 34, 100, 7.0, 63452, 63452, 63452, 18200, 81652, 52000, true, true, true, true, 22432, 14.2, '6:1', ARRAY['Finance','Nursing','Computer Science','Economics','Biology'], 'urban', 'https://www.upenn.edu', 'Penn is need-blind for international students and meets 100% of demonstrated need. The Wharton School is world-renowned for business. Strong interdisciplinary programs.', 6),
