('Dallas College', 'dallas-college', 'Dallas', 'TX', 'public', 100.00, NULL, NULL, 55, 5.0, 1770, 3330, 5790, 11000, 16790, 800, false, true, false, true, 80000, 6.3, '24:1', ARRAY['Business','Computer Science','Health Sciences','Liberal Arts','Engineering'], 'urban', 'https://www.dallascollege.edu', 'Dallas College (formerly DCCCD) offers extremely affordable tuition with transfer agreements to UT Dallas, UNT, and other Texas universities. Seven campuses across Dallas.', NULL),
('Maricopa Community Colleges', 'maricopa-cc', 'Tempe', 'AZ', 'public', 100.00, NULL, NULL, 45, 5.0, 2070, 7854, 7854, 11000, 18854, 800, false, true, false, true, 150000, 4.1, '22:1', ARRAY['Business','Liberal Arts','Health Sciences','Computer Science','Engineering'], 'urban', 'https://www.maricopa.edu', 'Maricopa is one of the largest community college systems with guaranteed transfer to ASU. MCCCD International Education program supports students. Very affordable.', NULL),
('Seattle Central College', 'seattle-central', 'Seattle', 'WA', 'public', 100.00, NULL, NULL, 52, 5.0, 4000, 4000, 10677, 13000, 23677, 1000, false, true, false, true, 14000, 15.3, '21:1', ARRAY['Business','Computer Science','Liberal Arts','Culinary Arts','Health Sciences'], 'urban', 'https://www.seattlecentral.edu', 'Seattle Central is one of the top community colleges for international students. Transfer pathways to UW Seattle. Located in vibrant Capitol Hill neighborhood.', NULL),
('Bellevue College', 'bellevue-college', 'Bellevue', 'WA', 'public', 100.00, NULL, NULL, 52, 5.0, 3855, 3855, 9831, 13000, 22831, 800, false, true, false, true, 25000, 10.7, '22:1', ARRAY['Computer Science','Business','Health Sciences','Liberal Arts','Engineering'], 'suburban', 'https://www.bellevuecollege.edu', 'Bellevue College is near Microsoft and Amazon headquarters. Strong CS and business programs with transfer pathways to UW. Large international student community.', NULL),
('Pasadena City College', 'pasadena-cc', 'Pasadena', 'CA', 'public', 100.00, NULL, NULL, 45, 5.0, 1104, 8136, 8136, 13000, 21136, 1500, false, true, false, true, 24000, 8.9, '28:1', ARRAY['Business','Liberal Arts','Engineering','Computer Science','Biology'], 'urban', 'https://www.pasadena.edu', 'Pasadena City College is a top California transfer school. Near Caltech and JPL. Strong STEM programs with pathways to UCLA, USC, and UC schools.', NULL),
('College of San Mateo', 'san-mateo', 'San Mateo', 'CA', 'public', 100.00, NULL, NULL, 45, 5.0, 1104, 5664, 6864, 14000, 20864, 1200, false, true, false, true, 8000, 8.5, '25:1', ARRAY['Business','Computer Science','Liberal Arts','Engineering','Biology'], 'suburban', 'https://www.collegeofsanmateo.edu', 'College of San Mateo is located between San Francisco and Silicon Valley. Strong transfer rates to UC Berkeley and other UCs. Small classes and personal attention.', NULL),
('Miami Dade College', 'miami-dade', 'Miami', 'FL', 'public', 100.00, NULL, NULL, 45, 5.0, 2759, 9655, 9655, 12000, 21655, 1500, false, true, false, true, 120000, 7.3, '26:1', ARRAY['Business','Health Sciences','Liberal Arts','Engineering','Computer Science'], 'urban', 'https://www.mdc.edu', 'Miami Dade College is the largest institution of higher education in the US. Very diverse student body. Affordable with transfer pathways to FIU and UF. Multiple campuses in Miami.', NULL);


