-- 3. SEED DATA — SCHOLARSHIPS
-- ============================================================

-- ---- FULL-RIDE SCHOLARSHIPS (10) ----

INSERT INTO scholarships (name, slug, provider, type, amount_min, amount_max, covers_tuition, covers_living, renewable, duration_years, eligible_countries, eligible_majors, min_gpa, min_toefl, min_ielts, education_level, income_requirement, first_gen_only, deadline, application_url, description, requirements, university_id) VALUES
('Mastercard Foundation Scholars Program', 'mastercard-foundation-scholars', 'Mastercard Foundation', 'full_ride', 60000, 80000, true, true, true, 4, ARRAY['All African countries'], NULL, 3.00, 80, 6.5, ARRAY['undergraduate','graduate'], 'Demonstrated financial need required', false, 'Varies by partner university', 'https://mastercardfdn.org/all/scholars/', 'The Mastercard Foundation Scholars Program provides comprehensive financial support to academically talented yet economically disadvantaged students from Africa. Covers tuition, accommodation, books, transportation, and living expenses. Available at partner universities including UC Berkeley, Duke, Michigan, and others.', 'Must be from an African country. Demonstrated financial need. Strong academic record. Commitment to giving back to community. Leadership potential.', NULL),
('Stamps Scholarship', 'stamps-scholarship', 'Stamps Family Charitable Foundation', 'full_ride', 50000, 80000, true, true, true, 4, NULL, NULL, 3.80, NULL, NULL, ARRAY['undergraduate'], NULL, false, 'Varies by partner university', 'https://www.stampsfoundation.org/', 'The Stamps Scholarship covers the full cost of attendance at 40+ partner universities including Georgia Tech, Purdue, Michigan, UVA, and Miami. Includes enrichment fund of $12,000-$16,000 for study abroad, research, and internships.', 'Nominated by partner university during admissions. Top academic achievement. Leadership and community service. Enrichment funds for unique experiences.', NULL),
('QuestBridge National College Match', 'questbridge-match', 'QuestBridge', 'full_ride', 60000, 85000, true, true, true, 4, NULL, NULL, 3.50, NULL, NULL, ARRAY['undergraduate'], 'Family income typically under $65,000', false, 'September (application), October (ranking)', 'https://www.questbridge.org/high-school-students/national-college-match', 'QuestBridge matches high-achieving, low-income students with full four-year scholarships at 50+ partner colleges including all Ivies, Stanford, MIT, and more. Covers tuition, room, board, books, and travel.', 'US citizen, permanent resident, or undocumented student. Household income typically under $65,000. Outstanding academic record despite financial hardship.', NULL),
('Gates Scholarship', 'gates-scholarship', 'Bill & Melinda Gates Foundation', 'full_ride', 50000, 80000, true, true, true, 4, NULL, NULL, 3.30, NULL, NULL, ARRAY['undergraduate'], 'Pell-eligible (US citizens/residents only)', false, 'September 15', 'https://www.thegatesscholarship.org/', 'The Gates Scholarship covers the full cost of attendance not already covered by financial aid and EFC. For Pell-eligible minority students. Note: Limited to US citizens/permanent residents but included for eligible international students with permanent residency.', 'Must be Pell-eligible. African American, American Indian, Asian/Pacific Islander, or Hispanic American. Minimum 3.3 GPA. US citizen or permanent resident.', NULL),
('Davis-UWC Scholars Program', 'davis-uwc-scholars', 'Davis United World College Scholars Program', 'full_ride', 40000, 75000, true, true, true, 4, NULL, NULL, 3.00, 80, 6.5, ARRAY['undergraduate'], 'Need-based', false, 'Varies by partner university', 'https://www.davisuwcscholars.org/', 'The Davis-UWC Scholars Program provides scholarships to graduates of United World Colleges attending one of 100+ partner universities in the US. Awards range from partial to full funding based on need.', 'Must be a graduate of a United World College (UWC). Admitted to a Davis-UWC partner university. Financial need demonstrated through CSS Profile or institutional application.', NULL),
('Coca-Cola Scholars Program', 'coca-cola-scholars', 'Coca-Cola Scholars Foundation', 'full_ride', 20000, 20000, false, false, true, 4, NULL, NULL, 3.00, NULL, NULL, ARRAY['undergraduate'], NULL, false, 'October 31', 'https://www.coca-colascholarsfoundation.org/', 'The Coca-Cola Scholars Program awards $20,000 scholarships to 150 high school seniors annually. Focuses on leadership, service, and academics. One of the most prestigious merit scholarships in the US.', 'Current high school senior. US citizen, permanent resident, or DACA. Minimum 3.0 GPA. Strong leadership and community service record.', NULL),
('Aga Khan Foundation International Scholarship', 'aga-khan-scholarship', 'Aga Khan Foundation', 'full_ride', 30000, 70000, true, true, true, 2, ARRAY['Bangladesh','India','Pakistan','Afghanistan','Tajikistan','Kyrgyzstan','Syria','Egypt','Kenya','Tanzania','Uganda','Madagascar','Mozambique'], NULL, 3.00, 80, 6.5, ARRAY['graduate'], 'Demonstrated financial need', false, 'March 31', 'https://www.akdn.org/our-agencies/aga-khan-foundation/international-scholarship-programme', 'The Aga Khan Foundation provides scholarships for postgraduate studies to outstanding students from developing countries who have no other means of financing. 50% grant and 50% loan. Covers tuition and living expenses.', 'From eligible developing country. Admitted to a reputable university. No other means of financing studies. Commitment to return to home country or developing world.', NULL),
('YSEALI Academic Fellowship', 'yseali-fellowship', 'US Department of State', 'full_ride', 25000, 40000, true, true, false, 1, ARRAY['Brunei','Cambodia','Indonesia','Laos','Malaysia','Myanmar','Philippines','Singapore','Thailand','Vietnam','Timor-Leste'], NULL, 3.00, 79, 6.5, ARRAY['undergraduate'], NULL, false, 'Varies (typically spring)', 'https://asean.usmission.gov/yseali/', 'YSEALI Academic Fellowships bring undergraduate students from ASEAN nations to US universities for one semester of academic study. Fully funded including travel, tuition, housing, and living expenses.', 'Citizen of an ASEAN country. Age 18-25. Currently enrolled in undergraduate program. Strong English proficiency. Interest in civic engagement, environment, or economic development.', NULL),
('EducationUSA Opportunity Funds', 'educationusa-opportunity', 'US Department of State', 'full_ride', 5000, 80000, true, true, false, 4, NULL, NULL, 3.50, 80, 6.5, ARRAY['undergraduate'], 'Demonstrated significant financial need', false, 'Varies by EducationUSA center', 'https://educationusa.state.gov/scholarships', 'EducationUSA Opportunity Funds help highly qualified students who are likely to be admitted to US universities with full financial aid but cannot afford the upfront costs of testing, applications, and travel. Works as a bridge to full university aid.', 'Must be identified by a local EducationUSA advising center. High academic achievement. Significant financial need. Strong potential for admission with full financial aid.', NULL),
('MasterCard Foundation Scholars at UC Berkeley', 'mastercard-ucb', 'Mastercard Foundation & UC Berkeley', 'full_ride', 70000, 75000, true, true, true, 4, ARRAY['All African countries'], NULL, 3.50, 80, 6.5, ARRAY['undergraduate','graduate'], 'Demonstrated financial need', false, 'November 30 (UC Berkeley deadline)', 'https://mastercardfdn.org/all/scholars/becoming-a-scholar/university-of-california-berkeley/', 'Full scholarship for African students at UC Berkeley covering tuition, housing, meals, books, health insurance, and travel. Includes mentoring, leadership development, and career support. One of the most comprehensive scholarships for African students.', 'Must be from sub-Saharan Africa. Admitted to UC Berkeley. Demonstrated financial need and academic excellence. Commitment to returning to Africa to contribute to community development.', (SELECT id FROM universities WHERE slug = 'uc-berkeley'));

-- ---- UNIVERSITY-SPECIFIC INTERNATIONAL MERIT SCHOLARSHIPS (15) ----

INSERT INTO scholarships (name, slug, provider, type, amount_min, amount_max, covers_tuition, covers_living, renewable, duration_years, eligible_countries, eligible_majors, min_gpa, min_toefl, min_ielts, education_level, income_requirement, first_gen_only, deadline, application_url, description, requirements, university_id) VALUES
('University of Alabama International Merit Scholarships', 'alabama-international-merit', 'University of Alabama', 'merit', 12000, 28000, true, false, true, 4, NULL, NULL, 3.00, 71, 6.0, ARRAY['undergraduate'], NULL, false, 'December 15 (priority)', 'https://scholarships.ua.edu/international/', 'Alabama offers automatic merit scholarships for international freshmen based on GPA. Awards range from $12,000 to full tuition ($28,000+). One of the most generous automatic scholarship programs for international students.', 'International freshman applicant. Based on unweighted GPA on 4.0 scale. Automatic consideration with admission application. Renewable with maintained GPA.', (SELECT id FROM universities WHERE slug = 'alabama')),
('Iowa International Merit Scholarships', 'iowa-international-merit', 'University of Iowa', 'merit', 5000, 15000, false, false, true, 4, NULL, NULL, 3.00, 80, 6.5, ARRAY['undergraduate'], NULL, false, 'February 1 (priority)', 'https://admissions.uiowa.edu/finances/scholarships-international-students', 'University of Iowa offers automatic merit scholarships for international students ranging from $5,000 to $15,000 annually. Combined with competitive tuition, Iowa is an affordable option for international students.', 'International freshman applicant. Based on academic record. Automatic consideration. Renewable with good academic standing.', (SELECT id FROM universities WHERE slug = 'uiowa')),
('USF Green and Gold Director Award', 'usf-green-gold', 'University of South Florida', 'merit', 4000, 12000, false, false, true, 4, NULL, NULL, 3.00, 79, 6.5, ARRAY['undergraduate'], NULL, false, 'January 15 (priority)', 'https://www.usf.edu/admissions/international/scholarships/', 'USF offers Green and Gold Director Awards for international freshmen based on academic achievement. Awards range from $4,000 to $12,000 per year, making USF very affordable for international students.', 'International freshman applicant. Strong academic record. Automatic consideration with admission. Renewable with maintained GPA.', (SELECT id FROM universities WHERE slug = 'usf')),
('ASU New American University Scholarship', 'asu-new-american', 'Arizona State University', 'merit', 5000, 16000, false, false, true, 4, NULL, NULL, 3.00, 61, 6.0, ARRAY['undergraduate'], NULL, false, 'Rolling', 'https://students.asu.edu/international/scholarships', 'ASU offers the New American University Scholarship for international students ranging from $5,000 to $16,000 per year. One of the most accessible merit scholarship programs for international students.', 'International freshman applicant. Based on GPA and test scores. Automatic consideration. Renewable with good academic standing.', (SELECT id FROM universities WHERE slug = 'asu')),
('BU Trustee Scholarship', 'bu-trustee', 'Boston University', 'merit', 25000, 58000, true, false, true, 4, NULL, NULL, 3.80, 90, 7.0, ARRAY['undergraduate'], NULL, false, 'December 1', 'https://www.bu.edu/admissions/tuition-aid/scholarships-financial-aid/first-year-merit/', 'Boston University Trustee Scholarships cover full tuition for the most exceptional applicants including international students. Presidential Scholarships cover 75% and Dean Scholarships cover 50%.', 'Must apply by Early Decision or Regular Decision deadline. Top academic achievement. Exceptional extracurricular involvement. No separate application required.', (SELECT id FROM universities WHERE slug = 'boston-university')),
('Brandeis Wien International Scholarship', 'brandeis-wien', 'Brandeis University', 'merit', 25000, 60000, true, true, true, 4, NULL, NULL, 3.50, 90, 7.0, ARRAY['undergraduate'], 'Need-based component', false, 'November 1 (ED) / January 2 (RD)', 'https://www.brandeis.edu/financial-aid/apply/international-students.html', 'The Wien International Scholarship at Brandeis covers full tuition and possibly room and board for exceptional international students. One of the most generous scholarships at any mid-tier university.', 'International student. Outstanding academic record. Demonstrated financial need. Strong personal qualities and leadership.', (SELECT id FROM universities WHERE slug = 'brandeis')),
('Emory University Scholarship Program', 'emory-merit', 'Emory University', 'merit', 16000, 32000, false, false, true, 4, NULL, NULL, 3.50, 100, 7.0, ARRAY['undergraduate'], NULL, false, 'November 15 (ED) / January 1 (RD)', 'https://apply.emory.edu/afford/scholarships-and-grants.html', 'Emory offers Dean and Emory Scholars awards to the most exceptional applicants including international students. Awards range from half to full tuition. Separate scholars application required.', 'Apply by regular admission deadline. Some require separate scholarship essay. Top academic achievement and extracurriculars.', (SELECT id FROM universities WHERE slug = 'emory')),
('Case Western Reserve University Merit Awards', 'case-western-merit', 'Case Western Reserve University', 'merit', 15000, 54000, true, false, true, 4, NULL, NULL, 3.50, 90, 7.0, ARRAY['undergraduate'], NULL, false, 'November 1 (EA) / January 15 (RD)', 'https://case.edu/admission/financial-aid/scholarships', 'Case Western offers merit scholarships up to full tuition for international students. Awards include the Distinguished Scholar, University Scholar, and Faculty Scholar awards.', 'International applicant with strong academic credentials. Automatic consideration with admission application. Some awards require separate application.', (SELECT id FROM universities WHERE slug = 'case-western')),
('American University Emerging Global Leader Scholarship', 'au-emerging-global-leader', 'American University', 'full_ride', 60000, 72000, true, true, true, 4, NULL, NULL, 3.80, 80, 6.5, ARRAY['undergraduate'], 'Demonstrated financial need', false, 'December 1', 'https://www.american.edu/admissions/international/emerging-global-leader.cfm', 'American University awards one full-ride scholarship per year to an international student who demonstrates leadership, academic excellence, and a commitment to positive civic and social change.', 'International student. Outstanding academic record (top 10%). Demonstrated financial need. Strong leadership and community engagement. Plan to return home to improve community.', (SELECT id FROM universities WHERE slug = 'american-university')),
('Tulsa International Student Merit Scholarships', 'tulsa-international-merit', 'University of Tulsa', 'merit', 10000, 44000, true, false, true, 4, NULL, NULL, 3.00, 80, 6.0, ARRAY['undergraduate'], NULL, false, 'January 15', 'https://admission.utulsa.edu/tuition-and-aid/scholarships/international-students/', 'University of Tulsa offers merit scholarships covering up to full tuition for international students. One of the most generous private university scholarship programs for internationals.', 'International applicant. Based on academic achievement and test scores. Automatic consideration with admission. Renewable with maintained GPA.', (SELECT id FROM universities WHERE slug = 'tulsa')),
('Minnesota Global Excellence Scholarship', 'umn-global-excellence', 'University of Minnesota', 'merit', 10000, 25000, false, false, true, 4, NULL, NULL, 3.50, 79, 6.5, ARRAY['undergraduate'], NULL, false, 'December 1', 'https://admissions.tc.umn.edu/costsaid/scholarships_international.html', 'UMN offers Global Excellence Scholarships of $10,000-$25,000 annually for outstanding international freshmen. Combines with affordable tuition to make UMN accessible.', 'International freshman applicant. Strong academic record. Automatic consideration with admission application. Renewable with good academic standing.', (SELECT id FROM universities WHERE slug = 'umn')),
('Purdue Merit Scholarships for International Students', 'purdue-international-merit', 'Purdue University', 'merit', 4000, 16000, false, false, true, 4, NULL, NULL, 3.50, 80, 6.5, ARRAY['undergraduate'], NULL, false, 'January 1', 'https://www.admissions.purdue.edu/costsandfinaid/internationalawards.php', 'Purdue offers merit-based scholarships for international students in engineering and sciences. Awards range from $4,000 to $16,000. Combined with frozen tuition, Purdue is very affordable.', 'International applicant to Purdue. Based on academic excellence. Automatic consideration with admission. Specific college may have additional awards.', (SELECT id FROM universities WHERE slug = 'purdue')),
('Ohio State International Scholarships', 'ohio-state-international', 'Ohio State University', 'merit', 5000, 15000, false, false, true, 4, NULL, NULL, 3.30, 79, 6.5, ARRAY['undergraduate'], NULL, false, 'November 1 (priority)', 'https://sfa.osu.edu/incoming-freshmen/international-students', 'Ohio State offers the Provost International Scholarship and other merit awards for international freshmen. Awards range from $5,000 to $15,000 per year.', 'International freshman applicant. Based on academic record and achievements. Automatic consideration with admission application.', (SELECT id FROM universities WHERE slug = 'ohio-state')),
('Indiana University Dean International Award', 'iu-dean-international', 'Indiana University Bloomington', 'merit', 6000, 15000, false, false, true, 4, NULL, NULL, 3.00, 79, 6.5, ARRAY['undergraduate'], NULL, false, 'February 1', 'https://ois.iu.edu/admissions/scholarships/index.html', 'IU Bloomington offers automatic merit scholarships for international students based on GPA. Dean International Award ranges from $6,000 to $15,000 annually.', 'International freshman applicant. Automatic based on GPA. Renewable with maintained GPA.', (SELECT id FROM universities WHERE slug = 'indiana')),
('NYU Abu Dhabi Full Scholarship', 'nyuad-full-scholarship', 'New York University Abu Dhabi', 'full_ride', 79000, 83000, true, true, true, 4, NULL, NULL, 3.50, 100, 7.5, ARRAY['undergraduate'], 'Need-based', false, 'January 5', 'https://nyuad.nyu.edu/en/admissions/financial-aid.html', 'NYU Abu Dhabi offers full-ride scholarships covering tuition, housing, dining, textbook allowance, travel, and health insurance. One of the most generous full-ride programs for international students globally.', 'Apply to NYU Abu Dhabi through Common App. Financial aid is 100% need-based and meets full demonstrated need for all admitted students regardless of nationality.', (SELECT id FROM universities WHERE slug = 'nyu'));
